const search = $('Get Active Saved Searches').item.json;
const newProperties = $('Get New Properties (last 6h)').all().map(i => i.json);

// Match properties against saved search criteria
const matches = newProperties.filter(prop => {
  if (search.max_price && prop.price > search.max_price) return false;
  if (search.min_price && prop.price < search.min_price) return false;
  if (search.min_bedrooms && prop.bedrooms < search.min_bedrooms) return false;
  if (search.max_bedrooms && prop.bedrooms > search.max_bedrooms) return false;
  if (search.province_filter && search.province_filter !== 'all' && prop.province !== search.province_filter) return false;
  if (search.city_filter && search.city_filter !== 'all' && !prop.city.toLowerCase().includes(search.city_filter.toLowerCase())) return false;
  if (search.property_type_filter && search.property_type_filter !== 'all' && prop.property_type !== search.property_type_filter) return false;
  return true;
});

if (matches.length === 0) return [];

const time = new Date().toLocaleTimeString('en-ZA', { hour: '2-digit', minute: '2-digit' });

const emailHtml = `
<!DOCTYPE html>
<html>
<head><style>
body{font-family:Arial,sans-serif;color:#333;margin:0;padding:0;}
.header{background:linear-gradient(135deg,#1a472a,#2d6a4f);color:white;padding:30px;text-align:center;}
.header h1{margin:0;font-size:24px;}
.header p{margin:5px 0 0;opacity:0.9;}
.content{padding:20px;}
.property{border:1px solid #e0e0e0;border-radius:10px;margin:15px 0;padding:20px;transition:box-shadow 0.2s;}
.property-title{font-size:18px;font-weight:bold;color:#1a472a;margin:0 0 8px;}
.price{font-size:24px;font-weight:bold;color:#2d6a4f;margin:8px 0;}
.details{color:#666;font-size:14px;margin:5px 0;}
.tag{background:#e8f5e9;color:#1a472a;padding:3px 10px;border-radius:12px;font-size:12px;display:inline-block;margin:2px;}
.cta{background:#1a472a;color:white;padding:12px 25px;text-decoration:none;border-radius:6px;display:inline-block;margin-top:12px;font-weight:bold;}
.footer{background:#f5f5f5;padding:20px;text-align:center;color:#999;font-size:12px;}
</style></head>
<body>
<div class="header">
  <h1>New Listings Alert</h1>
  <p>${matches.length} new propert${matches.length === 1 ? 'y' : 'ies'} matching "${search.search_name}"</p>
</div>
<div class="content">
  <p>Hi ${search.user_name || 'there'}, here are the latest listings matching your saved search.</p>
${matches.slice(0, 8).map(prop => `
  <div class="property">
    <div class="property-title">${prop.title}</div>
    <div class="price">R ${Number(prop.price).toLocaleString()}</div>
    <div class="details">
      <span class="tag">${prop.bedrooms} Bedrooms</span>
      <span class="tag">${prop.bathrooms} Bathrooms</span>
      <span class="tag">${prop.property_type}</span>
    </div>
    <div class="details">${prop.suburb ? prop.suburb + ', ' : ''}${prop.city}, ${prop.province}</div>
    <div class="details">${prop.size_sqm > 0 ? prop.size_sqm + ' m²' : ''}</div>
    <a href="${prop.url}" class="cta">View Property</a>
  </div>
`).join('')}
</div>
<div class="footer">
  <p>You're receiving this because of your saved search on PuraEstate.</p>
  <p><a href="https://puraestate.co.za/saved-searches/${search.id}/unsubscribe">Unsubscribe</a> | <a href="https://puraestate.co.za/saved-searches">Manage Alerts</a></p>
</div>
</body></html>`;

const smsText = `PuraEstate: ${matches.length} new listing${matches.length > 1 ? 's' : ''} for "${search.search_name}". Top pick: ${matches[0].title} - R${Number(matches[0].price).toLocaleString()} in ${matches[0].city}. Visit puraestate.co.za`;

return [{
  json: {
    search_id: search.id,
    user_email: search.user_email,
    user_name: search.user_name,
    user_phone: search.user_phone,
    notify_email: search.notify_email,
    notify_sms: search.notify_sms,
    notify_whatsapp: search.notify_whatsapp,
    search_name: search.search_name,
    matches_count: matches.length,
    email_html: emailHtml,
    sms_text: smsText,
    subject: `${matches.length} new listing${matches.length > 1 ? 's' : ''} for "${search.search_name}"`
  }
}];
